class MyAPMClient(Client):
    def process_transaction(self, transaction):
        # Validate untrusted input
        if not isinstance(transaction['data'], dict) or 'request' not in transaction['data']:
            elasticapm.capture_exception()
            return

        request = transaction['data']['request']
        response = transaction['data']['response']

        # Capture full request/response data
        elasticapm.begin_transaction(
            name='my-transaction',
            type='request',
            resource=request['url'],
            span_type='http.request',
            span_subtype='http.response',
        )
        elasticapm.capture_span(
            name='capture-request-data',
            description='Capture full request data',
            start_time=elasticapm.now(),
        )

        # Capture SQL queries
        if 'sql' in transaction['data']:
            sql_queries = transaction['data']['sql']
            for query in sql_queries:
                elasticapm.capture_span(
                    name='capture-sql-query',
                    description=query,
                    start_time=elasticapm.now(),
                )

        # Capture stack traces
        try:
            elasticapm.capture_exception()
        except Exception as e:
            elasticapm.capture_exception()

        # End transaction
        elasticapm.end_transaction(
            name='my-transaction',
            result='success' if response['status_code'] == 200 else 'failure',
        )

